mapper.select:
AND c.创建人编码 = #{creatorId}
AND ( -- 搜索合同号 c.合同号 LIKE CONCAT('%', #{keyword}, '%') -- 搜索正式客户的名称和联系人 OR EXISTS ( SELECT 1 FROM CUSTOMER cu WHERE cu.客户编码 = c.客户编码 AND ( cu.企业名称 LIKE CONCAT('%', #{keyword}, '%') OR cu.联系人 LIKE CONCAT('%', #{keyword}, '%') ) ) -- 搜索临时客户的名称和联系人（从customer_snapshot中提取） OR ( JSON_UNQUOTE(JSON_EXTRACT(c.customer_snapshot, '$.customerType')) = 'TEMPORARY' AND ( JSON_UNQUOTE(JSON_EXTRACT(c.customer_snapshot, '$.customerName')) LIKE CONCAT('%', #{keyword}, '%') OR JSON_UNQUOTE(JSON_EXTRACT(c.customer_snapshot, '$.contactPerson')) LIKE CONCAT('%', #{keyword}, '%') ) ) )
ORDER BY c.更新时间 DESC, c.合同编号 DESC
